async function pageFunction(context) {
  const { $, request, log } = context;
  const listings = [];

  $('li.wrap.css-qo0afh').each(function() {
    const el = $(this);
    const title = el.find('h6').text().trim();
    const priceText = el.find('[data-testid="ad-price"]').text().trim();
    const price = parseInt(priceText.replace(/[^0-9]/g, '')) || null;
    const location = el.find('[data-testid="location-date"]').text().split(' - ')[0].trim();
    const url = el.find('a').attr('href');
    const listingId = url?.match(/ID([A-Za-z0-9]+)/)?.[1] ?? url?.split('-').pop()?.replace('.html','');

    if (!price || price < 100000) return;

    listings.push({
      listingId,
      title,
      price,
      location,
      url: url?.startsWith('http') ? url : 'https://www.olx.pt' + url,
      source: 'apify_olx'
    });
  });

  log.info(`OLX: Found ${listings.length} listings on ${request.url}`);
  return listings;
}

