const item = $input.first().json;

function extractCityOLX(location) {
  if (!location) return null;
  const l = location.toLowerCase();
  if (l.includes('lisboa') || l.includes('lisbon')) return 'Lisboa';
  if (l.includes('cascais')) return 'Cascais';
  if (l.includes('sintra')) return 'Sintra';
  if (l.includes('porto') || l.includes('foz')) return 'Porto';
  if (l.includes('algarve') || l.includes('faro') || l.includes('vilamoura') || l.includes('lagos') || l.includes('albufeira')) return 'Algarve';
  if (l.includes('comporta') || l.includes('setúbal') || l.includes('setubal')) return 'Setúbal';
  if (l.includes('braga') || l.includes('guimarães')) return 'Braga';
  if (l.includes('madeira') || l.includes('funchal')) return 'Madeira';
  if (l.includes('açores') || l.includes('ponta delgada')) return 'Açores';
  return location.split(',')[0].trim() || null;
}

function extractTipoOLX(url, title) {
  const h = `${url} ${title}`.toLowerCase();
  if (h.includes('quinta') || h.includes('herdade')) return 'quinta';
  if (h.includes('predio') || h.includes('edificio')) return 'prédio';
  if (h.includes('terreno')) return 'terreno';
  if (h.includes('moradia') || h.includes('casa') || h.includes('vivenda')) return 'moradia';
  if (h.includes('comercial') || h.includes('loja')) return 'comercial';
  return 'apartamento';
}

const urgencyKeywords = ['urgente','venda rápida','preço a negociar','oportunidade','reduzido'];
const titleLower = (item.title ?? '').toLowerCase();
const isUrgent = urgencyKeywords.some(k => titleLower.includes(k));

return [{ json: {
  source: 'apify_olx',
  source_listing_id: String(item.listingId ?? item.id ?? ''),
  source_url: item.url,
  nome: `Proprietário OLX ${item.listingId ?? ''}`,
  tipo_ativo: extractTipoOLX(item.url ?? '', item.title ?? ''),
  localizacao: item.location ?? null,
  cidade: extractCityOLX(item.location),
  price_ask: item.price ?? null,
  contacto: item.phone ?? null,
  urgency: isUrgent ? 'high' : 'unknown',
  status: 'new',
  raw_data: item
}}];
